INSERT INTO public.note (id, patient_id, doctor_id, appointment_id, note_type, category, content, consultation_duration, created_at, transplant_indication, surgical_planning) VALUES (26, 20, 5, 27, 'conduta', 'transplante_capilar', 'O transplante capilar é uma etapa do tratamento e não o tratamento completo. É fundamental a adesão ao acompanhamento clínico para manutenção dos resultados. O sucesso cirúrgico depende do controle contínuo da queda capilar e da resposta individual do paciente ao tratamento.', 14, '2025-12-02 13:21:53.242842', 'nao', '{"norwood": null, "previous_transplant": "nao", "transplant_location": null, "case_type": "primaria", "body_hair": true, "eyebrow_transplant": false, "beard_transplant": false, "frontal": false, "crown": false, "complete": false, "complete_body_hair": false, "surgical_planning_text": "calvicie muito extensa\narea doadora ruim\npenso em 2500 capilar \n1000 barba e 2000 peito\n\nainda sim ficara ralo com desenho conservador"}');
